from sympy import factorint
from functools import lru_cache
from multiprocessing import Pool, cpu_count
from collections import defaultdict
from itertools import combinations_with_replacement
from math import isqrt
from fractions import Fraction
@lru_cache(maxsize=None)
def sigma(n: int) -> int:
    factors = factorint(n)
    result = 1
    for p, a in factors.items():
        result *= (p**(a + 1) - 1) // (p - 1)
    return result
@lru_cache(maxsize=None)
def dedekind_psi(n: int) -> Fraction:
    factors = factorint(n)
    result = Fraction(n, 1)
    for p in factors:
        result *= Fraction(p + 1, p)
    return result
def process_n(n):
    return n, int(sigma(n) * dedekind_psi(n))
def find_xyzt_quads(start, end):
    with Pool(cpu_count()) as pool:
        results = pool.map(process_n, range(start, end + 1))
    groups = defaultdict(list)
    for n, f in results:
        groups[f].append(n)
    quads = []
    for fval, nums in groups.items():
        nums.sort()
        for x, y, z in combinations_with_replacement(nums, 3):
            rhs = fval - x*x - y*y - z*z
            if rhs >= 0:
                t = isqrt(rhs)
                if t*t == rhs:
                    quads.append((x, y, z, t))
    return quads
